param([string]$EventsPath="ENGREMIAT_MEMORY/operative/events/events.jsonl",[string]$HomePath="ENGREMIAT_MEMORY/logseq/pages/Home.md",[string]$ReportPath="reports/dev-visual-memory-operative/e02-live-maps-navigation/logseq-home-validation-report.json")
$ErrorActionPreference="Stop"
[Console]::OutputEncoding=[System.Text.Encoding]::UTF8
function ED($p){ if($p -and !(Test-Path -LiteralPath $p)){ New-Item -ItemType Directory -Path $p -Force | Out-Null } }
function WJ($p,$o){ ED (Split-Path -Parent $p); $o | ConvertTo-Json -Depth 100 | Set-Content -LiteralPath $p -Encoding UTF8 }
$events=@(); if(Test-Path -LiteralPath $EventsPath -PathType Leaf){ foreach($l in Get-Content -LiteralPath $EventsPath -Encoding UTF8){ if([string]::IsNullOrWhiteSpace($l)){continue}; try{$events+=($l|ConvertFrom-Json)}catch{} } }
$lastOk=@($events|Where-Object{$_.status -eq "OK"}|Select-Object -Last 5); $lastErr=@($events|Where-Object{$_.status -eq "ERR" -or $_.status -eq "NO_GO"}|Select-Object -Last 5); $active="ENGREMIAT_DEV_VISUAL_MEMORY_OPERATIVE_002"; $next="E03_DASHBOARD_OPERATIVO"; $gateCount=0; if(Test-Path -LiteralPath "data/gates"){$gateCount=@(Get-ChildItem -LiteralPath "data/gates" -Recurse -File -ErrorAction SilentlyContinue).Count}; $readiness="UNKNOWN"; if(Test-Path -LiteralPath "data/dev/context-snapshot.json" -PathType Leaf){ try{$ctx=Get-Content -LiteralPath "data/dev/context-snapshot.json" -Raw -Encoding UTF8|ConvertFrom-Json; if($ctx.readiness.current_percent){$readiness=[string]$ctx.readiness.current_percent}}catch{} }
$lines=@("# Home","","- objective_active: [["+ $active +"]]","- stage_active: E02 Live maps and navigation","- readiness: "+$readiness,"- gates_detected: "+$gateCount,"- events_count: "+$events.Count,"- next: "+$next,"","## Quick maps","- [[OPERATIVE_OVERVIEW]]","- [[ENGREMIAT_CORE_MVP_MAP]]","- [[ERRORS_MAP]]","- [[DECISIONS_MAP]]","- [[GATES_MAP]]","- [[WORKERS_MAP]]","","## Last OK"); foreach($e in @($lastOk)){ $lines += "- OK "+$e.stage_id+" "+$e.source_path }; $lines += ""; $lines += "## Last ERR or NO_GO"; foreach($e in @($lastErr)){ $lines += "- "+$e.status+" "+$e.stage_id+" "+$e.source_path }; $lines += ""; $lines += "## Operational entry"; $lines += "- Sync: tools/memory/Sync-VisualMemory.ps1"; $lines += "- Dashboard next: E03_DASHBOARD_OPERATIVO"; ED (Split-Path -Parent $HomePath); Set-Content -LiteralPath $HomePath -Value $lines -Encoding UTF8; Set-Content -LiteralPath "ENGREMIAT_MEMORY/Home.md" -Value $lines -Encoding UTF8; $ok=($lines -join "`n") -match "objective_active" -and ($lines -join "`n") -match "next" -and ($lines -join "`n") -match "GATES_MAP"; $rep=[ordered]@{objective_id="ENGREMIAT_DEV_VISUAL_MEMORY_OPERATIVE_002";stage_id="E02";step_id="P02.1.2";status=$(if($ok){"OK"}else{"NO_GO"});validation_passed=$ok;home=$HomePath;events_count=$events.Count;gates_detected=$gateCount;readiness=$readiness;next=$next;updated_at=(Get-Date).ToString("s")}; WJ $ReportPath $rep; if(-not $ok){Write-Host "ERR logseq_home=False"; exit 1}; Write-Host ("OK logseq_home=True events="+$events.Count+" gates="+$gateCount+" report="+$ReportPath)
